import "./App.css";

import { Routes, Route, useLocation } from "react-router-dom";

import Menu from "./components/menu/Menu";
import Footer from "./components/footer/Footer";

import Home from "./pages/home/Home";
import About from "./pages/about/About";
import Works from "./pages/works/Works";
import Contact from "./pages/contact/Contact";
import Blog from "./pages/blog/Blog";

import SampleProject from "./pages/sampleproject/SampleProject";
import SampleBlog from "./pages/sampleblog/SampleBlog";

import { AnimatePresence } from "framer-motion";

function App() {
  const location = useLocation();
  const showFooter = location.pathname !== "/";

  return (
    <>
      <Menu />
      <AnimatePresence mode="wait">
        <Routes location={location} key={location.pathname}>
          <Route index element={<Home />} />
          <Route path="/about" element={<About />} />
          <Route path="/works" element={<Works />} />
          <Route path="/blog" element={<Blog />} />
          <Route path="/contact" element={<Contact />} />
          <Route path="/sample-project" element={<SampleProject />} />
          <Route path="/sample-blog" element={<SampleBlog />} />
        </Routes>
      </AnimatePresence>
      {showFooter && <Footer />}
    </>
  );
}

export default App;

@font-face {
  font-family: "Rosseta";
  src: url("/src/assets/fonts/Rosseta.otf") format("opentype");
  font-weight: 300;
  font-style: normal;
  font-display: swap;
}

@font-face {
  font-family: "Wremena";
  src: url("/src/assets/fonts/Wremena_Light.otf") format("opentype");
  font-weight: 300;
  font-style: normal;
  font-display: swap;
}

:root {
  --color-bg: #0d0d11;
  --color-bg-light: #131317;
  --color-bg-lighter: #2e2e34;
  --color-text-primary: #fff;
  --color-text-secondary: #4a4a51;
  --color-accent: #0604f0;
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100%;
  background-color: var(--color-bg);
  font-family: "Wremena";
  overflow-x: hidden;
}

h1 {
  text-transform: uppercase;
