}

.stats .stats-item-1 {
  flex: 1;
  background-color: var(--accent1);
}

.stats .stats-item-2 {
  flex: 3;
  background-color: var(--accent3);
}

.stats .stats-item-3 {
  flex: 2;
  background-color: var(--fg);
  color: var(--bg);
}

.stats .stats-item-1,
.stats .stats-item-2,
.stats .stats-item-3 {
  aspect-ratio: 16/7;
  padding: 2em;
  border-radius: 1em;
}

.stats .stats-col {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

@media (max-width: 1000px) {
  .about-hero {
    padding: 8em 2em 4em 2em;
  }

  .about-hero .about-hero-header h1 {
    font-size: 4rem;
  }

  .about-hero .about-hero-bio {
    width: 100%;
  }

  .about-hero .about-hero-portrait {
    width: 25%;
    top: 50%;
    transform: translate(-50%, -50%) rotate(0deg);
  }

  .about-hero .about-hero-portrait img {
    position: absolute;
    height: 110%;
  }

  .about-copy .about-copy-content {
    width: 100%;
  }

  .about-copy .about-copy-content h3 {
    font-size: 1.5rem;
  }

  .about-copy .tag {
    display: none;
  }

  .skills .skills-copy {
    padding: 0;
    width: 100%;
    text-align: center;
    border: none;
    border-radius: 0;
  }

  .stats .stats-row {
    flex-direction: column;
  }

  .stats .stats-col {
    width: 100%;
    text-align: center;
    gap: 4em;
  }

  .stats .stats-header {
    gap: 2em;
    margin-bottom: 2em;
  }
}

/* contact - hero */
.contact {
  position: relative;
  width: 100vw;
  height: 100svh;
  padding: 2em;
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  background-color: var(--bg);
  overflow: hidden;
}

.contact .trail-img {
  position: absolute;
  width: 150px;
  height: 150px;
  object-fit: cover;
  border-radius: 1em;
  transform-origin: center;
  pointer-events: none;
  will-change: transform;
}

.contact-card {
  border-radius: 1em;
  display: flex;
  flex-direction: column;
  gap: 0.5em;
}

.contact .contact-card-header-main {
  margin-bottom: 4em;
  display: flex;
  flex-direction: column;
  gap: 1em;
}

.contact .contact-card-header-main p {
  width: 50%;
}

.contact p.contact-card-header {
  padding: 0.25em 0.5em;
  border-radius: 0.25em;
  width: max-content;
  background-color: var(--fg);
  color: var(--bg);
}

.contact .contact-symbol {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  height: 1rem;
}

@media (max-width: 1000px) {
  .contact {
    height: 100svh;
    padding: 2em;
    flex-direction: column;
    text-align: center;
    justify-content: flex-end;
    gap: 4em;
  }

  .contact .contact-card {
    width: 100%;
    justify-content: center;
    align-items: center;
    text-align: center;
  }

  .contact .contact-card-header-main p {
    width: 100%;
  }

  .contact .contact-symbol {
    display: none;
  }
}

