  useGSAP(
    () => {
      gsap.to(menuBtnOpen.current, {
        y: isOpen ? -24 : 0,
        duration: 1,
        delay: 0.75,
        ease: "power2.out",
      });
      gsap.to(menuBtnClose.current, {
        y: isOpen ? 0 : 24,
        duration: 1,
        delay: 0.75,
        ease: "power2.out",
      });
