    [isOpen],
    { scope: container }
  );

  return (
    <div
      ref={container}
      className={`menu-toggle ${isOpen ? "opened" : "closed"}`}
      onClick={toggleMenu}
    >
      <div className="menu-copy">
        <p id="menu-open" ref={menuBtnOpen}>
