  bottom: 2em;
  right: 2em;
  width: 30%;
  height: 50px;
  display: flex;
  gap: 0.5em;
}

.slider .preview {
  position: relative;
  flex: 1;
  cursor: pointer;
}

.slider .preview::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.25);
  transition: 0.3s ease-in-out;
}

.slider .preview.active::after {
