}

.project-date {
  text-align: center;
  margin: 2em 0 4em 0;
  clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%);
}

.next-project {
  text-align: center;
  margin: 6em 0 0 0;
}

.project-date p {
  position: relative;
  transform: translateY(24px);
  will-change: transform;
}

.project-page .img {
