.carousel {
  width: 100%;
  cursor: -webkit-grab;
  cursor: grab;
}
.carousel.dragging {
  cursor: -webkit-grabbing;
  cursor: grabbing;
}
.carousel--wrap {
  white-space: nowrap;
}
.carousel--item {
  display: inline-block;
  width: 30vw;
  padding: 3vw;
