:root {
  --bg: #e4e3db;
  --text-color: #e4e3db;
  --project-primary: #e88640;
  --project-footer: #0a0a0a;
}
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  line-height: 1;
}

h1::selection,
h2::selection,
h3::selection,
h4::selection,
h5::selection,
h6::selection,
p::selection,
a::selection {
  background: var(--text-color);
  color: var(--bg);
}

html,
body {
  width: 100%;
  height: 100%;
  background: var(--bg);
  color: var(--text-color);
  overflow-x: hidden;
}

/* container */
.container {
  width: 100vw;
}

.site-content {
  width: 75%;
  margin: 0 auto;
}

@media (max-width: 900px) {
  .site-content {
    width: 80%;
  }
}

/* text global styles */
h1,
h2,
h3,
h4 {
  font-family: "Canopee";
  font-weight: 400;
}

p,
a {
  font-family: "Acid Grotesk";
  font-weight: 400;
  line-height: 1.4;
  text-decoration: none;
}

p {
  opacity: 0.5;
}

h1 {
  font-size: 20vw;
}

h2 {
  font-size: 7vw;
}

h3 {
  font-size: 3vw;
}

h4 {
  font-size: 2.5vw;
}

p {
  font-size: 1.5vw;
}

a {
  font-size: 1.5vw;
}

@media (max-width: 900px) {
  h2 {
    font-size: 10vw;
  }

  h3 {
    font-size: 7vw;
  }

  h4 {
    font-size: 6vw;
  }

  p {
    font-size: 4vw;
  }

  a {
    font-size: 4vw;
  }
}

/* hero */
.hero {
  position: relative;
  width: 100%;
  height: 150vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  margin-bottom: 10em;
}

.hero .hero-header {
  padding-top: 20vh;
}

.hero .hero-header h1 {
  position: relative;
  top: 220px;
  line-height: 0.8;
  text-align: center;
  text-transform: uppercase;
  font-weight: 500;
}

.hero-header-wrapper {
  position: relative;
}

.about-h1-revealer {
  content: "";
  position: absolute;
  display: block;
  top: 200px;
  left: -50px;
  width: 125%;
  height: 155%;
  background: var(--bg);
}

.hero .hero-img {
  position: relative;
  width: 500px;
  height: 600px;
  margin-top: -25%;
  overflow: clip;
  clip-path: inset(0 0 0 0);
  opacity: 0;
  border-radius: 10px;
  border: 2px solid var(--text-color);
}

.hero .hero-img img {
  width: 100%;
  object-fit: cover;
}

@media (max-width: 900px) {
  .hero {
    height: 80vh;
    margin-bottom: 5em;
  }

  .hero .hero-header {
    padding-top: 40vh;
  }

  .hero .hero-img {
    width: 50%;
  }
}

/* sub-hero */
.sub-hero {
  width: 100%;
  height: 50vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-content: center;
  margin: 5em 0;
}

.sub-hero h2 {
  font-weight: 500;
  text-align: center;
  text-transform: uppercase;
  color: transparent;
  -webkit-text-stroke: 1px rgba(255, 255, 255, 0.75);
}

.sub-hero h2 span {
  color: #000;
}

/* about */
.about {
  margin: 5em 0;
}

.about h3 {
  text-align: center;
}

